  project_name = var.project_name
  common_tags = {
    Project = local.project_name
    ManagedBy = "Terraform"
  }
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 4.0"
    }
  }
}", "variables.tf": "variable "aws_region" {
  type        = string
  default     = "us-east-1"
  description = "AWS region"
}

variable "project_name" {
  type        = string
  default     = "drag-proj-1"
  description = "Project name"
}", "outputs.tf": "output "api_gateway_url" {
  value       = aws_apigatewayv2_api.main.api_endpoint
  description = "API Gateway endpoint URL"
}

output "ecs_cluster_name" {
  value       = aws_ecs_cluster.main.name
  description = "ECS cluster name"
}", "provider.tf": "provider "aws" {
  region = var.aws_region
}", "networking.tf": "resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags       = local.common_tags
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
  tags   = local.common_tags
}

resource "aws_subnet" "public_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "${var.aws_region}a"
  tags              = local.common_tags
}

resource "aws_subnet" "public_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "${var.aws_region}b"
  tags              = local.common_tags
}

resource "aws_subnet" "private_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "${var.aws_region}a"
  tags              = local.common_tags
}

resource "aws_subnet" "private_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.4.0/24"
  availability_zone = "${var.aws_region}b"
  tags              = local.common_tags
}

resource "aws_eip" "nat" {
  domain = "vpc"
}

resource "aws_nat_gateway" "main" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.public_1.id
  tags          = local.common_tags
}", "security.tf": "resource "aws_security_group" "ecs" {
  name        = "${local.project_name}-ecs"
  description = "ECS security group"
  vpc_id      = aws_vpc.main.id
  tags        = local.common_tags
}

resource "aws_security_group_rule" "ecs_inbound" {
  type              = "ingress"
  from_port         = 0
  to_port           = 0
  protocol          = "-1"
  cidr_blocks       = ["0.0.0.0/0"]
  security_group_id = aws_security_group.ecs.id
}", "compute.tf": "resource "aws_ecs_cluster" "main" {
  name = local.project_name
  tags = local.common_tags
}

resource "aws_ecs_task_definition" "main" {
  family                = local.project_name
  network_mode          = "awsvpc"
  requires_compatibilities = ["FARGATE"]
  cpu                    = 256
  memory                = 512
  execution_role_arn    = aws_iam_role.ecs_task_execution.arn
  tags                  = local.common_tags
}

resource "aws_ecs_service" "main" {
  name            = local.project_name
  cluster         = aws_ecs_cluster.main.name
  task_definition = aws_ecs_task_definition.main.arn
  launch_type      = "FARGATE"
  network_configuration {
    security_groups = [aws_security_group.ecs.id]
    subnets         = [aws_subnet.private_1.id, aws_subnet.private_2.id]
    assign_public_ip = false
  }
}", "apigateway.tf": "resource "aws_apigatewayv2_api" "main" {
  name          = "${local.project_name}-api"
  protocol_type = "HTTP"
  cors_configuration {
    allow_headers = ["content-type"]
    allow_origins = ["*"]
    allow_methods = ["*"]
  }
  tags = local.common_tags
}", "iam.tf": "resource "aws_iam_role" "ecs_task_execution" {
  name        = "${local.project_name}-ecs-task-execution"
  description = "ECS task execution role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ecs-tasks.amazonaws.com"
        }
      }
    ]
  })
  tags = local.common_tags
}

resource "aws_iam_role_policy_attachment" "ecs_task_execution" {
  role       = aws_iam_role.ecs_task_execution.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonECSTaskExecutionRolePolicy"
}"}}, "cost": {"estimated_monthly_cost": 113.5, "currency": "USD", "breakdown": [{"service": "aws_ecs (node_1_1772018833454)", "estimated_monthly_cost": 75.0, "details": "Scale: medium, label: 🐳 ECS Service"}, {"service": "aws_vpc (node_2_1772018838519)", "estimated_monthly_cost": 35.0, "details": "Scale: medium, label: 🔒 VPC"}, {"service": "aws_apigatewayv2 (node_6_1772018852345)", "estimated_monthly_cost": 3.5, "details": "Scale: medium, label: API Gateway"}]}, "visual": {"nodes": [{"id": "node_6_1772018852345", "type": "default", "position": {"x": 390.0, "y": 230.0}, "data": {"label": "🌐 API Gateway", "service_type": "aws_apigatewayv2", "config_summary": "{"runtime": null, "memory": null, "instance_type": null, "engine": null, "capacity": null, "extra": "}, "style": {"background": "#FF9900", "border": "2px solid #CC7A00", "borderRadius": "8px", "padding": "10px", "color": "white", "fontWeight": "bold", "width": "180px"}}, {"id": "node_1_1772018833454", "type": "default", "position": {"x": 390.0, "y": 380.0}, "data": {"label": "🐳 🐳 ECS Service", "service_type": "aws_ecs", "config_summary": "{"runtime": null, "memory": null, "instance_type": null, "engine": null, "capacity": null, "extra": "}, "style": {"background": "#FF9900", "border": "2px solid #CC7A00", "borderRadius": "8px", "padding": "10px", "color": "white", "fontWeight": "bold", "width": "180px"}}, {"id": "node_2_1772018838519", "type": "default", "position": {"x": 280.0, "y": 680.0}, "data": {"label": "🔒 🔒 VPC", "service_type": "aws_vpc", "config_summary": "{"runtime": null, "memory": null, "instance_type": null, "engine": null, "capacity": null, "extra": "}, "style": {"background": "#248814", "border": "2px solid #1A6610", "borderRadius": "8px", "padding": "10px", "color": "white", "fontWeight": "bold", "width": "180px"}}, {"id": "node_3_1772018841234", "type": "default", "position": {"x": 500.0, "y": 680.0}, "data": {"label": "🛡️ Security Group", "service_type": "aws_security_group", "config_summary": 