ll, "capacity": null, "extra": {"vpc_id": "netflix_vpc", "rules_count": 1}}}, {"id": "db_sg", "type": "aws_security_group", "label": "Database Security Group", "config": {"runtime": null, "memory": null, "instance_type": null, "engine": "postgres", "capacity": null, "extra": {"vpc_id": "netflix_vpc", "rules_count": 1}}}, {"id": "netflix_alb", "type": "aws_alb", "label": "Netflix ALB", "config": {"runtime": null, "memory": null, "instance_type": null, "engine": null, "capacity": null, "extra": {"lb_type": "application"}}}, {"id": "netflix_ecs_cluster", "type": "aws_ecs_cluster", "label": "Netflix ECS Cluster", "config": {"runtime": null, "memory": null, "instance_type": null, "engine": null, "capacity": null, "extra": {}}}, {"id": "netflix_ecs_service", "type": "aws_ecs", "label": "Netflix ECS Service", "config": {"runtime": null, "memory": 512, "instance_type": null, "engine": null, "capacity": null, "extra": {"cpu": 1024, "container_port": 8080, "desired_count": 2, "image": "nginx:latest"}}}, {"id": "netflix_fargate_profile", "type": "aws_fargate", "label": "Netflix Fargate Profile", "config": {"runtime": null, "memory": null, "instance_type": null, "engine": null, "capacity": null, "extra": {"cluster_id": "netflix_ecs_cluster", "namespace": "default"}}}, {"id": "netflix_db", "type": "aws_rds", "label": "Netflix RDS Instance", "config": {"runtime": null, "memory": null, "instance_type": "db.t2.micro", "engine": "postgres", "capacity": null, "extra": {"storage": 20, "multi_az": true}}}, {"id": "netflix-content-bucket", "type": "aws_s3", "label": "Netflix Content Bucket", "config": {"runtime": null, "memory": null, "instance_type": null, "engine": null, "capacity": null, "extra": {"versioning": true}}}, {"id": "netflix_cf", "type": "aws_cloudfront", "label": "Netflix CloudFront Distribution", "config": {"runtime": null, "memory": null, "instance_type": null, "engine": null, "capacity": null, "extra": {"origin_domain": "netflix-content-bucket.s3.amazonaws.com"}}}], "edges": [{"from": "netflix_vpc", "to": "public_subnet_1", "label": "contains"}, {"from": "netflix_vpc", "to": "public_subnet_2", "label": "contains"}, {"from": "netflix_vpc", "to": "private_subnet_1", "label": "contains"}, {"from": "netflix_vpc", "to": "private_subnet_2", "label": "contains"}, {"from": "netflix_vpc", "to": "web_sg", "label": "contains"}, {"from": "netflix_vpc", "to": "app_sg", "label": "contains"}, {"from": "netflix_vpc", "to": "db_sg", "label": "contains"}, {"from": "netflix_alb", "to": "netflix_ecs_service", "label": "routes_to"}, {"from": "netflix_ecs_cluster", "to": "netflix_fargate_profile", "label": "fargate profile"}, {"from": "netflix_ecs_service", "to": "netflix_db", "label": "connects_to"}, {"from": "netflix_cf", "to": "netflix-content-bucket", "label": "originates_from"}, {"from": "netflix_db", "to": "db_sg", "label": "uses"}, {"from": "netflix_ecs_service", "to": "app_sg", "label": "uses"}, {"from": "netflix_alb", "to": "web_sg", "label": "uses"}]}, "terraform_files": {"files": {"main.tf": "locals {
  project_name = "netflix-system-design"
  environment = "dev"
  tags = {
    Project = local.project_name
    Environment = local.environment
  }
}

terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 4.0.0"
    }
  }
}", "variables.tf": "variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "vpc_cidr_block" {
  description = "VPC CIDR block"
  type        = string
  default     = "10.0.0.0/16"
}

variable "public_subnet_1_cidr" {
  description = "Public subnet 1 CIDR"
  type        = string
  default     = "10.0.1.0/24"
}

variable "public_subnet_2_cidr" {
  description = "Public subnet 2 CIDR"
  type        = string
  default     = "10.0.2.0/24"
}

variable "private_subnet_1_cidr" {
  description = "Private subnet 1 CIDR"
  type        = string
  default     = "10.0.3.0/24"
}

variable "private_subnet_2_cidr" {
  description = "Private subnet 2 CIDR"
  type        = string
  default     = "10.0.4.0/24"
}

variable "db_instance_class" {
  description = "RDS instance class"
  type        = string
  default     = "db.t2.micro"
}

variable "db_engine" {
  description = "RDS database engine"
  type        = string
  default     = "postgres"
}

variable "db_storage" {
  description = "RDS database storage"
  type        = number
  default     = 20
}

variable "ecs_service_desired_count" {
  description = "ECS service desired count"
  type        = number
  default     = 2
}

variable "ecs_service_container_port" {
  description = "ECS service container port"
  type        = number
  default     = 8080
}
", "provider.tf": "provider "aws" {
  region = var.aws_region
}
", "networking.tf": "resource "aws_vpc" "netflix_vpc" {
  cidr_block = var.vpc_cidr_block
  tags       = local.tags
}

resource "aws_subnet" "public_subnet_1" {
  vpc_id            = aws_vpc.netflix_vpc.id
  cidr_block        = var.public_subnet_1_cidr
  availability_zone = "${var.aws_region}a"
  map_public_ip_on_launch = true
  tags              = local.tags
}

resource "aws_subnet" "public_subnet_2" {
  vpc_id            = aws_vpc.netflix_vpc.id
  cidr_block        = var.public_subnet_2_cidr
  availability_zone = "${var.aws_region}b"
  map_public_ip_on_launch = true
  tags              = local.tags
}

resource "aws_subnet" "private_subnet_1" {
  vpc_id            = aws_vpc.netflix_vpc.id
  cidr_block        = var.private_subnet_1_cidr
  availability_zone = "${var.aws_region}a"
  tags              = local.tags
}

resource "aws_subnet" "private_subnet_2" {
  vpc_id            = aws_vpc.netflix_vpc.id
  cidr_block        = var.private_subnet_2_cidr
  availability_zone = "${var.aws_region}b"
  tags              = local.tags
}

resource "aws_internet_gateway" "netflix_igw" {
  vpc_id = aws_vpc.netflix_vpc.id
  tags   = local.tags
}

resource "aws_eip" "nat_eip" {
  domain = "vpc"
}

resource "aws_nat_gateway" "netflix_nat" {
  allocation_id = aws_eip.nat_eip.id
  subnet_id     = aws_subnet.public_subnet_1.id
  tags          = local.tags
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.netflix_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.netflix_igw.id
  }
  tags = local.tags
}

resource "aws_route_table" "private_rt" {
  vpc_id = aws_vpc.netflix_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.netflix_nat.id
  }
  tags = local.tags
}

resource "aws_route_table_association" "public_subnet_1_assoc" {
  subnet_id      = aws_subnet.public_subnet_1.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "public_subnet_2_assoc" {
  subnet_id      = aws_subnet.public_subnet_2.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "private_subnet_1_assoc" {
  subnet_id      = aws_subnet.private_subnet_1.id
  route_table_id = aws_route_table.private_rt.id
}

resource "aws_route_table_association" "private_subnet_2_assoc" {
  subnet_id      = aws_subnet.private_subnet_2.id
  route_table_id = aws_route_table.private_rt.id
}", "security.tf": "resource "aws_security_group" "web_sg" {
  name        = "web-sg"
  description = "Web security group"
  vpc_id      = aws_vpc.netflix_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = local.tags
}

resource "aws_security_group" "app_sg" {
  name        = "app-sg"
  description = "App security group"
  vpc_id      = aws_vpc.netflix_vpc.id

  ingress {
    from_port       = var.ecs_service_container_port
    to_port         = var.ecs_service_container_port
    protocol        = "tcp"
    security_groups = [aws_security_group.web_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = local.tags
}

resource "aws_security_group" "db_sg" {
  name        = "db-sg"
  description = "Database security group"
  vpc_id      = aws_vpc.netflix_vpc.id

  ingress {
    from_port       = 5432
    to_port         = 5432
    protocol        = "tcp"
    security_groups = [aws_security_group.app_sg.id]
  }

  tags = local.tags
}", "compute.tf": "resource "aws_alb" "netflix_alb" {
  name            = "netflix-alb"
  subnets         = [aws_subnet.public_subnet_1.id, aws_subnet.public_subnet_2.id]
  security_groups = [aws_security_group.web_sg.id]
  tags            = local.tags
}

resource "aws_alb_target_group" "netflix_tg" {
  name        = "netflix-tg"
  port        = var.ecs_service_container_port
  protocol    = "HTTP"
  vpc_id      = aws_vpc.netflix_vpc.id
  target_type = "ip"
  tags        = local.tags
}

resource "aws_alb_listener" "netflix_alb_listener" {
  load_balancer_arn = aws_alb.netflix_alb.id
  port              = 80
  protocol          = "HTTP"

  default_action {
    target_group_arn = aws_alb_target_group.netflix_tg.id
    type             = "forward"
  }
}

resource "aws_ecs_cluster" "netflix_ecs_cluster" {
  name = "netflix-ecs-cluster"
  tags = local.tags
}

resource "aws_ecs_task_definition" "netflix_task_definition" {
  family                = "netflix-task-definition"
  cpu                    = 1024
  memory                = 512
  network_mode          = "awsvpc"
  requires_compatibilities = ["FARGATE"]
  execution_role_arn    = aws_iam_role.ecs_task_execution_role.arn
  container_definitions = jsonencode([
    {
      name        = "netflix-container"
      image       = "nginx:latest"
      cpu         = 0
      essential   = true
      portMappings = [
        {
          containerPort = var.ecs_service_container_port
          hostPort      = var.ecs_service_container_port
          protocol      = "tcp"
        }
      ]
    }
  ])
  tags = local.tags
}

resource "aws_ecs_service" "netflix_ecs_service" {
  name            = "netflix-ecs-service"
  cluster         = aws_ecs_cluster.netflix_ecs_cluster.name
  task_definition = aws_ecs_task_definition.netflix_task_definition.arn
  desired_count   = var.ecs_service_desired_count
  launch_type      = "FARGATE"

  network_configuration {
    security_groups = [aws_security_group.app_sg.id]
    subnets         = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
    assign_public_ip = "DISABLED"
  }

  load_balancer {
    target_group_arn = aws_alb_target_group.netflix_tg.id
    container_name   = "netflix-container"
    container_port   = var.ecs_service_container_port
  }

  depends_on = [aws_alb_listener.netflix_alb_listener]
  tags       = local.tags
}", "storage.tf": "resource "aws_s3_bucket" "netflix_content_bucket" {
  bucket = "netflix-content-bucket"
  tags   = local.tags
}

resource "aws_s3_bucket_versioning" "netflix_content_bucket_versioning" {
  bucket = aws_s3_bucket.netflix_content_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "netflix_content_bucket_encryption" {
  bucket = aws_s3_bucket.netflix_content_bucket.id
  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}", "database.tf": "resource "aws_db_instance" "netflix_db" {
  identifier           = "netflix-db"
  instance_class       = var.db_instance_class
  engine               = var.db_engine
  allocated_storage    = var.db_storage
  db_name              = "netflixdb"
  username             = "netflixuser"
  password             = "netflixpassword"
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  db_subnet_group_name = aws_db_subnet_group.netflix_db_subnet_group.name
  skip_final_snapshot = true
  tags                 = local.tags
}

resource "aws_db_subnet_group" "netflix_db_subnet_group" {
  name        = "netflix-db-subnet-group"
  description = "Netflix DB subnet group"
  subnet_ids  = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
  tags        = local.tags
}", "cdn.tf": "resource "aws_cloudfront_distribution" "netflix_cf" {
  origin {
    domain_name = aws_s3_bucket.netflix_content_bucket.bucket_regional_domain_name
    origin_id   = "netflix-content-bucket"
  }

  enabled = true

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "netflix-content-bucket"

    forwarded_values {
      query_string = false

      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "allow-all"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
  tags = local.tags
}", "iam.tf": "resource "aws_iam_role" "ecs_task_execution_role" {
  name        = "ecs-task-execution-role"
  description = "ECS task execution role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ecs-tasks.amazonaws.com"
        }
      }
    ]
  })
  tags = local.tags
}

resource "aws_iam_policy" "ecs_task_execution_policy" {
  name        = "ecs-task-execution-policy"
  description = "ECS task execution policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "ecr:GetAuthorizationToken",
          "ecr:BatchGetImage",
          "ecr:GetDownloadUrlForLayer",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Effect = "Allow"
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "ecs_task_execution_attach" {
  role       = aws_iam_role.ecs_task_execution_role.name
  policy_arn = aws_iam_policy.ecs_task_execution_policy.arn
}", "outputs.tf": "output "alb_dns_name" {
  value       = aws_alb.netflix_alb.dns_name
  description = "DNS name of the ALB"
}

output "ecs_cluster_name" {
  value       = aws_ecs_cluster.netflix_ecs_cluster.name
  description = "Name of the ECS cluster"
}

output "s3_bucket_name" {
  value       = aws_s3_bucket.netflix_content_bucket.id
  description = "Name of the S3 bucket"
}

output "cloudfront_distribution_domain" {
  value       = aws_cloudfront_distribution.netflix_cf.domain_name
  description = "Domain name of the CloudFront distribution"
}
